if doc.custom_source_of_creation == 'FB_APP':
    if doc.custom_customer_type == 'Company':
        for i in doc.get('custom_poc'):
            if frappe.db.exists("Contact", {"custom_mobile_number":i.custom_mobile_number}):
                con = frappe.get_doc('Contact',i.contact)
                con.append("links",{
                    "link_doctype":"Lead",
                    "link_name":doc.name
                })
                con.save()

if doc.customer_type == 'Company':
    for i in doc.get('point_of_contact'):
        if frappe.db.exists("Contact", {"mobile_number":i.mobile_number}):
            con = frappe.get_doc('Contact',i.contact)
            con.append("links",{
                "link_doctype":"Lead",
                "link_name":doc.name
            })
            con.save()

# Keep the Opportunity's custom_quotation_status in sync with the Quotation status.
if doc.custom_opportunity_from and frappe.db.exists("Opportunity", doc.custom_opportunity_from):
    frappe.db.set_value(
        "Opportunity", doc.custom_opportunity_from, "custom_quotation_status", doc.status,
        update_modified=False,
    )
